import { useEffect, useMemo, useState, FC } from 'react';

import { TimeAgoProps } from './TimeAgo.types';

export const getTimeUnits = (secondsAgo: number) => {
  const minutesAgo = Math.floor(secondsAgo / 60);
  const hoursAgo = Math.floor(minutesAgo / 60);
  const daysAgo = Math.floor(hoursAgo / 24);

  return {
    daysAgo,
    hoursAgo,
    minutesAgo,
  };
};

export const getFormattedTimeAgoEn = (secondsAgo: number) => {
  if (secondsAgo === 0) {
    return '';
  }

  const { daysAgo, hoursAgo, minutesAgo } = getTimeUnits(secondsAgo);

  if (minutesAgo === 0) {
    return `${secondsAgo} second${secondsAgo > 1 ? 's' : ''} ago`;
  }

  if (hoursAgo === 0) {
    return `${minutesAgo} minute${minutesAgo > 1 ? 's' : ''} ago`;
  }

  if (daysAgo === 0) {
    return `${hoursAgo} hour${hoursAgo > 1 ? 's' : ''} ago`;
  }

  return `${daysAgo} day${daysAgo > 1 ? 's' : ''} ago`;
};

export const getFormattedTimeAgoEs = (secondsAgo: number) => {
  if (secondsAgo === 0) {
    return '';
  }

  const { daysAgo, hoursAgo, minutesAgo } = getTimeUnits(secondsAgo);

  if (minutesAgo === 0) {
    return `Hace ${secondsAgo} segundo${secondsAgo > 1 ? 's' : ''}`;
  }

  if (hoursAgo === 0) {
    return `Hace ${minutesAgo} minuto${minutesAgo > 1 ? 's' : ''}`;
  }

  if (daysAgo === 0 && hoursAgo === 1) {
    return `${hoursAgo} hora antes`;
  } else if (daysAgo === 0) {
    return `Hace ${hoursAgo} hora${hoursAgo > 1 ? 's' : ''}`;
  }

  return `Hace ${daysAgo} día${daysAgo > 1 ? 's' : ''}`;
};

const TimeAgo: FC<TimeAgoProps> = ({ lang, timestamp }) => {
  const [seconds, setSeconds] = useState(0);

  useEffect(() => {
    setSeconds(Math.floor(Date.now() / 1000) - timestamp);

    const intervalId = setInterval(() => {
      setSeconds((currentValue) => currentValue + 1);
    }, 1000);

    // cleanup function
    return () => clearInterval(intervalId);
  }, [timestamp]);

  const formattedTimeAgo = useMemo(
    () =>
      lang === 'es'
        ? getFormattedTimeAgoEs(seconds)
        : getFormattedTimeAgoEn(seconds),
    [lang, seconds],
  );

  return <>{formattedTimeAgo}</>;
};

export default TimeAgo;
